function add(num1 , num2){
    return num1 + num2;
}

function sub(num1 , num2){
    return num1 - num2;
}

function mul(num1 , num2){
    return num1 * num2;
}                   
function div(num1 , num2){   
    if(num2 === 0){
        return "Error: Division by zero is not allowed.";
    }
    return num1 / num2;
}
const math={
    add,
    sub,
    mul,
    div
}
export { math }; 